// Generates the inlinable engine block (fail-successfully + dispatch, no import/export)
// and injects it between // <ENGINE-BUNDLE:start> / <ENGINE-BUNDLE:end> markers in each TARGET.
import { readFile, writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';

const LIB = new URL('./lib/', import.meta.url);
const TARGETS = ['./orchestration-audit.workflow.mjs', './librarian.workflow.mjs'];
const START = '// <ENGINE-BUNDLE:start>';
const END = '// <ENGINE-BUNDLE:end>';

// NOTE: source files must NOT use `export default` — the strip regex below would corrupt it.
function strip(src) {
  return src
    .replace(/^\s*import\s+\{[^}]*\}\s+from\s+['"]\.\/fail-successfully\.mjs['"];?\s*$/m, '')
    .replace(/^export\s+/gm, '');          // `export function` → `function`, `export const` → `const`
}

export async function buildBundle() {
  const engine = strip(await readFile(new URL('fail-successfully.mjs', LIB), 'utf8'));
  const dispatch = strip(await readFile(new URL('dispatch.mjs', LIB), 'utf8'));
  if (/\bimport\b/.test(engine) || /\bimport\b/.test(dispatch)) {
    throw new Error('strip() left a bare import — add a strip rule for the new import');
  }
  return `${START}\n// GENERATED by scripts/build-engine-bundle.mjs — do not edit; run \`npm run build:engine\`.\n${engine}\n${dispatch}\n${END}`;
}

async function inject(block, relPath) {
  const url = new URL(relPath, import.meta.url);
  const file = fileURLToPath(url);
  const src = await readFile(file, 'utf8');
  const re = new RegExp(`${START}[\\s\\S]*?${END}`);
  if (!re.test(src)) throw new Error(`markers not found in ${relPath}`);
  await writeFile(file, src.replace(re, block));
}

if (process.argv.includes('--emit')) {
  const block = await buildBundle();
  for (const t of TARGETS) {
    try { await inject(block, t); } catch (e) { console.error(`skip ${t}: ${e.message}`); }
  }
}
